FILES['src/modules/m04_long_dynamic_memory/imit/long_dynamic_memory_inputs.py'] = 'from __future__ import annotations\nfrom typing import Any, Dict\nimport torch\n\ndef _randn(batch:int=1, dim:int=256, scale:float=0.25)->torch.Tensor:\n    torch.manual_seed(404)\n    return torch.randn(batch, dim) * float(scale)\n\ndef _scalar(value:float)->torch.Tensor:\n    return torch.tensor([[float(value)]], dtype=torch.float32)\n\ndef make_m04_fake_out()->Dict[str, Any]:\n    return {"focus_context": _randn(1,256), "event_dream_replay": {"replay_context": _randn(1,256), "event_salience": _scalar(0.50)}}\n\ndef make_m04_inner_object()->Dict[str, Any]:\n    return {"z_obj": _randn(1,128), "slot_token": "slot:imit", "object_confidence": _scalar(0.65)}\n\nclass FakeM4PassportManager:\n    def __init__(self, context_dim:int=256)->None:\n        self.context_dim=int(context_dim)\n        self.passports={"obj:imit": {"token":"obj:imit","replay_z":_randn(1,self.context_dim),"confidence_ema":0.72,"last_similarity":0.82,"dynamic_score_ema":0.35,"lives_in_slot":1,"last_sentence":"imitated stable object identity","episode_summary":"imitated passport episode"}}\n    def observe(self, obj:Dict[str,Any], *, event_memory=None, dream_mode:bool=False, global_step:int=0)->Dict[str,Any]:\n        del obj,event_memory,dream_mode,global_step\n        return {"passport_token":"obj:imit","passport_confidence_ema":0.72,"passport_similarity":0.82,"passport_dynamic_score":0.35,"passport_count":float(len(self.passports)),"passport_slot":1.0,"passport_created":False,"passport_sentence":"imitated stable object identity","passport_episode_summary":"imitated passport episode","passport_source":"imit_passport"}\n    def select_for_replay(self, token:str="")->Dict[str,Any]:\n        return self.passports.get(token or "obj:imit", self.passports["obj:imit"])\n\ndef make_m04_input()->Dict[str, Any]:\n    return {"out": make_m04_fake_out(), "obj": make_m04_inner_object(), "passport_manager": FakeM4PassportManager(256), "event_memory": None, "dream_mode": True, "global_step": 1}\n\n__all__=["FakeM4PassportManager","make_m04_fake_out","make_m04_inner_object","make_m04_input"]\n'

FILES['src/modules/m05_world_model_attention_workspace/imit/focus_feedback_inputs.py'] = 'from __future__ import annotations\nfrom typing import Dict\nimport torch\n\ndef make_m05_focus_feedback_input(*, batch:int=1, seed_gate:float=0.10)->Dict[str, torch.Tensor]:\n    torch.manual_seed(505)\n    return {\n        "workspace_seed": torch.randn(batch,256),\n        "focus_context_seed": torch.randn(batch,256),\n        "focus_context_seed_gate": torch.tensor([[float(seed_gate)]], dtype=torch.float32).expand(batch,1),\n        "preconscious_seed": torch.randn(batch,192),\n    }\n\ndef make_m05_zero_seed_input(*, batch:int=1)->Dict[str, object]:\n    torch.manual_seed(506)\n    return {"workspace_seed": torch.randn(batch,256), "focus_context_seed": None, "focus_context_seed_gate": None, "preconscious_seed": torch.randn(batch,192)}\n\n__all__=["make_m05_focus_feedback_input","make_m05_zero_seed_input"]\n'

FILES['src/modules/m11_motivational_homeostasis/imit/emotional_drive_inputs.py'] = 'from __future__ import annotations\nfrom typing import Any, Dict\nimport torch\n\ndef _randn(batch:int, dim:int, scale:float=0.25)->torch.Tensor:\n    torch.manual_seed(1111)\n    return torch.randn(batch, dim) * float(scale)\n\ndef _scalar(value:float)->torch.Tensor:\n    return torch.tensor([[float(value)]], dtype=torch.float32)\n\ndef make_m11_m5_out(*, coherence:float=0.65, curiosity:float=0.45)->Dict[str,Any]:\n    return {\n        "focus_context": _randn(1,256),\n        "workspace_out": _randn(1,256),\n        "object_repr": _randn(1,128),\n        "object_imagery": {"object_confidence": _scalar(0.62)},\n        "preconscious_thoughts": {"thought_candidate": _randn(1,192), "workspace_seed": _randn(1,192), "candidate_delta": _randn(1,192,0.05)},\n        "preconscious_reflection_out": {"reflection": _randn(1,128), "model_confidence": _scalar(0.58)},\n        "memory": {"memory_context": _randn(1,256)},\n        "values": {"coherence": _scalar(coherence), "curiosity": _scalar(curiosity), "value_latent": _randn(1,64)},\n        "imagined": {"imagined_value": _scalar(0.15), "imagined_touch": _randn(1,16,0.05)},\n    }\n\ndef make_m11_obs()->Dict[str, torch.Tensor]:\n    return {"tactile": torch.ones(1,16)*0.05}\n\ndef make_m11_input()->Dict[str,Any]:\n    return {"out": make_m11_m5_out(), "obs": make_m11_obs()}\n\n__all__=["make_m11_m5_out","make_m11_obs","make_m11_input"]\n'

FILES['src/modules/m13_autobiographical_memory/imit/autobiographical_memory_inputs.py'] = 'from __future__ import annotations\nfrom typing import Any, Dict\nimport torch\n\ndef _randn(batch:int, dim:int, scale:float=0.25)->torch.Tensor:\n    torch.manual_seed(1313)\n    return torch.randn(batch, dim) * float(scale)\n\ndef _scalar(value:float)->torch.Tensor:\n    return torch.tensor([[float(value)]], dtype=torch.float32)\n\ndef make_m13_out()->Dict[str,Any]:\n    return {\n        "focus_context": _randn(1,256),\n        "affect": {"affect_latents": _randn(1,12), "valence": _scalar(0.10), "arousal": _scalar(0.50), "stress_latent": _scalar(0.25), "panic_latent": _scalar(0.10), "curiosity_latent": _scalar(0.70)},\n        "long_dynamic_memory": {"identity_token": "obj:imit", "dynamic_identity_context": _randn(1,256)},\n        "event_dream_replay": {"replay_context": _randn(1,256)},\n    }\n\ndef make_m13_obs()->Dict[str, torch.Tensor]:\n    return {"reward": _scalar(0.0), "done": _scalar(0.0)}\n\ndef make_m13_input()->Dict[str,Any]:\n    return {"obs": make_m13_obs(), "out": make_m13_out(), "global_step": 1}\n\n__all__=["make_m13_out","make_m13_obs","make_m13_input"]\n'

FILES['scripts/module_lab/module_imit_registry.py'] = 'from __future__ import annotations\nfrom typing import Callable, Dict\n\nfrom src.modules.m01_object_imagery.imit.sensor_inputs import make_m01_fake_obs\nfrom src.modules.m02_event_dream_replay.imit.event_dream_replay_inputs import make_m02_input\nfrom src.modules.m03_self_action_causality.imit.motor_guard_inputs import make_m03_motor_output\nfrom src.modules.m04_long_dynamic_memory.imit.long_dynamic_memory_inputs import make_m04_input\nfrom src.modules.m05_world_model_attention_workspace.imit.focus_feedback_inputs import make_m05_focus_feedback_input\nfrom src.modules.m11_motivational_homeostasis.imit.emotional_drive_inputs import make_m11_input\nfrom src.modules.m13_autobiographical_memory.imit.autobiographical_memory_inputs import make_m13_input\n\nIMIT_REGISTRY: Dict[str, Callable] = {\n    "m01": make_m01_fake_obs,\n    "m02": make_m02_input,\n    "m03": make_m03_motor_output,\n    "m04": make_m04_input,\n    "m05": make_m05_focus_feedback_input,\n    "m11": make_m11_input,\n    "m13": make_m13_input,\n}\n\ndef get_imitator(module_name:str)->Callable:\n    key=str(module_name).lower().strip()\n    if key not in IMIT_REGISTRY:\n        raise KeyError(f"unknown imitator {module_name!r}; available={sorted(IMIT_REGISTRY)}")\n    return IMIT_REGISTRY[key]\n\n__all__=["IMIT_REGISTRY","get_imitator"]\n'

FILES['scripts/module_lab/run_module_imit_registry.py'] = 'from __future__ import annotations\nimport argparse, json\nfrom typing import Any\nimport torch\nfrom scripts.module_lab.module_imit_registry import IMIT_REGISTRY, get_imitator\n\ndef summarize(value:Any)->Any:\n    if torch.is_tensor(value):\n        return {"type":"tensor","shape":list(value.shape),"finite":bool(torch.isfinite(value).all().item())}\n    if isinstance(value,dict):\n        return {k:summarize(v) for k,v in value.items()}\n    if isinstance(value,(list,tuple)):\n        return [summarize(v) for v in value[:3]]\n    return value\n\ndef main()->None:\n    parser=argparse.ArgumentParser()\n    parser.add_argument("--module", default="all")\n    args=parser.parse_args()\n    names=sorted(IMIT_REGISTRY) if args.module=="all" else [args.module]\n    result={}\n    for name in names:\n        result[name]=summarize(get_imitator(name)())\n    print(json.dumps(result, ensure_ascii=False, indent=2))\n\nif __name__=="__main__":\n    main()\n'

FILES['tests/module_contracts/test_per_module_imit_layout_contract.py'] = 'from __future__ import annotations\nimport torch\n\ndef test_per_module_imit_registry_imports():\n    from scripts.module_lab.module_imit_registry import IMIT_REGISTRY\n    assert {"m01","m02","m03","m04","m05","m11","m13"}.issubset(set(IMIT_REGISTRY))\n\ndef test_m02_imitator_returns_processed_internal_inputs_not_raw_m1():\n    from src.modules.m02_event_dream_replay.imit.event_dream_replay_inputs import make_m02_input\n    out, event_memory, dream_mode = make_m02_input()\n    assert "focus_context" in out\n    assert "affect" in out\n    assert "autobiographical_memory" in out\n    assert "long_dynamic_memory" in out\n    assert isinstance(event_memory, list)\n    assert dream_mode is True\n    assert "left" not in out and "right" not in out and "depth" not in out\n\ndef test_m04_imitator_uses_inner_object_not_raw_sensors():\n    from src.modules.m04_long_dynamic_memory.imit.long_dynamic_memory_inputs import make_m04_input\n    packet = make_m04_input()\n    assert "obj" in packet and "z_obj" in packet["obj"]\n    assert "out" in packet and "focus_context" in packet["out"]\n    assert "left" not in packet["out"] and "right" not in packet["out"]\n\ndef test_m05_imitator_returns_focus_seed_boundary_inputs():\n    from src.modules.m05_world_model_attention_workspace.imit.focus_feedback_inputs import make_m05_focus_feedback_input\n    packet = make_m05_focus_feedback_input()\n    assert tuple(packet["workspace_seed"].shape) == (1,256)\n    assert tuple(packet["focus_context_seed"].shape) == (1,256)\n    assert tuple(packet["focus_context_seed_gate"].shape) == (1,1)\n    assert tuple(packet["preconscious_seed"].shape) == (1,192)\n    assert bool(torch.isfinite(packet["workspace_seed"]).all().item())\n'

FILES['docs/architecture/module_imit_layout.md'] = '# Per-module `imit/` layout\n\nCentral `scripts/module_lab/` remains only a launcher/registry.\n\nInput imitation belongs to each module:\n\n```text\nsrc/modules/m01_object_imagery/imit/sensor_inputs.py\nsrc/modules/m02_event_dream_replay/imit/event_dream_replay_inputs.py\nsrc/modules/m03_self_action_causality/imit/motor_guard_inputs.py\nsrc/modules/m04_long_dynamic_memory/imit/long_dynamic_memory_inputs.py\nsrc/modules/m05_world_model_attention_workspace/imit/focus_feedback_inputs.py\nsrc/modules/m11_motivational_homeostasis/imit/emotional_drive_inputs.py\nsrc/modules/m13_autobiographical_memory/imit/autobiographical_memory_inputs.py\n```\n\nRegistry:\n\n```text\nscripts/module_lab/module_imit_registry.py\nscripts/module_lab/run_module_imit_registry.py\n```\n\nRun:\n\n```bash\npython scripts/module_lab/run_module_imit_registry.py --module all\npytest tests/module_contracts/test_per_module_imit_layout_contract.py\n```\n\nArchitectural rule:\n\n```text\nM1 -> M5 -> M11 -> M2 -> FocusFeedbackBoundary -> M5\n      |             ^\n      v             |\n     M4 ------------+\n                   M13 -> M2\n```\n\nM2 imitator must not receive raw sensors (`left/right/depth`) directly.\nM4 imitator must receive `inner_object / z_obj`, not raw sensors.\n'

FILES['README_module_imit_layout_patch_v1.md'] = "# module_imit_layout_patch_v1\n\nMoves module input imitation into each module's own `imit/` directory.\n\nInstall:\n\n```bash\nunzip -o module_imit_layout_patch_v1.zip -d .\npython scripts/apply_module_imit_layout_patch_v1.py\n```\n\nCheck:\n\n```bash\npython scripts/module_lab/run_module_imit_registry.py --module all\npytest tests/module_contracts/test_per_module_imit_layout_contract.py\n```\n\nThe central lab remains a launcher. Actual fake inputs live next to modules.\n"

IMIT_DIRS = [
    "src/modules/m01_object_imagery/imit",
    "src/modules/m02_event_dream_replay/imit",
    "src/modules/m03_self_action_causality/imit",
    "src/modules/m04_long_dynamic_memory/imit",
    "src/modules/m05_world_model_attention_workspace/imit",
    "src/modules/m11_motivational_homeostasis/imit",
    "src/modules/m13_autobiographical_memory/imit",
]

def ensure_init_files() -> None:
    for rel in IMIT_DIRS:
        d = ROOT / rel
        d.mkdir(parents=True, exist_ok=True)
        init = d / "__init__.py"
        if not init.exists():
            init.write_text("", encoding="utf-8")
            print(f"[ok] created {rel}/__init__.py")
        else:
            print(f"[skip] {rel}/__init__.py exists")

def write_files() -> None:
    for rel, content in FILES.items():
        target = ROOT / rel
        target.parent.mkdir(parents=True, exist_ok=True)
        if target.exists() and target.read_text(encoding="utf-8") == content:
            print(f"[skip] {rel}: unchanged")
            continue
        target.write_text(content, encoding="utf-8")
        print(f"[ok] wrote {rel}")

def main() -> int:
    ensure_init_files()
    write_files()
    print("\nRun:")
    print("  python scripts/module_lab/run_module_imit_registry.py --module all")
    print("  pytest tests/module_contracts/test_per_module_imit_layout_contract.py")
    return 0

if __name__ == "__main__":
    try:
        raise SystemExit(main())
    except Exception as e:
        print(f"\n[ERROR] {e}", file=sys.stderr)
        raise
